            StartTimeUtc = startTime.ToUniversalTime(),
            EndTimeUtc = endTime.ToUniversalTime(),
            StartTimeOfDay = startTimeOfDay,
            EndTimeOfDay = endTimeOfDay,
            RepeatIntervalUnit = IntervalUnit.Minute,
            RepeatInterval = 60
