        IJobDetail job = JobBuilder.Create<NoOpJob>()
            .WithIdentity("DummyJob", "DEFAULT")
            .Build();

        ITrigger myTrigger = TriggerBuilder.Create()
            .ForJob(job)
            .WithIdentity("MyIdentity", "DEFAULT")
            .WithDailyTimeIntervalSchedule(s => s
                .StartingDailyAt(new TimeOfDay(12, 0, 0))
                .EndingDailyAt(new TimeOfDay(15, 0, 0))
                .OnEveryDay()
            )
            .Build();

        ((DailyTimeIntervalTriggerImpl) myTrigger).EndTimeOfDay = new TimeOfDay(16, 0, 0);
    }

    [Test]
    public void TestInfinitiveLoop()
    {
        var trigger = (IOperableTrigger) TriggerBuilder.Create()
            .WithDailyTimeIntervalSchedule(x => x
                .InTimeZone(TZConvert.GetTimeZoneInfo("GTB Standard Time"))
                .StartingDailyAt(new TimeOfDay(0, 0, 0))
                .EndingDailyAt(new TimeOfDay(22, 0, 0))
                .WithInterval(15, IntervalUnit.Minute)
                .WithMisfireHandlingInstructionDoNothing()
            )
            .Build();

        var from = new DateTimeOffset(2018, 3, 25, 0, 0, 0, TimeSpan.Zero);
        var to = new DateTimeOffset(2018, 3, 27, 0, 0, 0, TimeSpan.Zero);
        var times = TriggerUtils.ComputeFireTimesBetween(trigger, null, from, to);
        Assert.That(times, Has.Count.LessThan(200));
    }

    /// <summary>
    /// Regression test for https://github.com/quartznet/quartznet/issues/859
    /// GetFireTimeAfter should not mutate the trigger's StartTimeUtc field.
    /// </summary>
    [Test]
    public void GetFireTimeAfterShouldNotMutateStartTimeUtc()
    {
        DateTimeOffset originalStartTime = DateBuilder.DateOf(0, 0, 0, 1, 1, 2024);
        var trigger = new DailyTimeIntervalTriggerImpl
        {
            StartTimeUtc = originalStartTime,
            StartTimeOfDay = new TimeOfDay(8, 0, 0),
            EndTimeOfDay = new TimeOfDay(17, 0, 0),
            RepeatIntervalUnit = IntervalUnit.Hour,
            RepeatInterval = 1
        };

        // Call with a time after the daily start time to exercise the code path
        // that previously mutated startTimeUtc
        DateTimeOffset afterTime = DateBuilder.DateOf(10, 0, 0, 1, 1, 2024);
        trigger.GetFireTimeAfter(afterTime);

        Assert.That(trigger.StartTimeUtc, Is.EqualTo(originalStartTime),
            "StartTimeUtc should not be modified by GetFireTimeAfter");

        // Also verify ComputeFirstFireTimeUtc doesn't mutate it
        trigger.StartTimeUtc = originalStartTime;
        trigger.ComputeFirstFireTimeUtc(null);

        Assert.That(trigger.StartTimeUtc, Is.EqualTo(originalStartTime),
            "StartTimeUtc should not be modified by ComputeFirstFireTimeUtc");
    }

    [Test]
    public void DoNothing_WithMisfireThreshold_PreservesWithinThresholdFireTime()
    {
        var startTime = new DateTimeOffset(2025, 1, 1, 10, 0, 0, TimeSpan.Zero);
        var frozenNow = new DateTimeOffset(2025, 1, 1, 10, 2, 30, TimeSpan.Zero);
        var threshold = TimeSpan.FromSeconds(60);

        var trigger = new DailyTimeIntervalTriggerImpl(new FixedTimeProvider(frozenNow))
        {
            Key = new TriggerKey("test", "test"),
            StartTimeUtc = startTime,
            StartTimeOfDay = new TimeOfDay(0, 0, 0),
            EndTimeOfDay = new TimeOfDay(23, 59, 59),
            RepeatInterval = 2,
            RepeatIntervalUnit = IntervalUnit.Minute,
            MisfireInstruction = MisfireInstruction.DailyTimeIntervalTrigger.DoNothing
        };
        trigger.ComputeFirstFireTimeUtc(null);

        trigger.UpdateAfterMisfire(null, threshold);

        DateTimeOffset? nextFire = trigger.GetNextFireTimeUtc();
        Assert.IsNotNull(nextFire);
        Assert.That(nextFire.Value, Is.EqualTo(new DateTimeOffset(2025, 1, 1, 10, 2, 0, TimeSpan.Zero)),
            "Should preserve the 10:02 fire time that is within the misfire threshold");
    }

    private sealed class FixedTimeProvider(DateTimeOffset utcNow) : TimeProvider
    {
        public override DateTimeOffset GetUtcNow() => utcNow;
    }
}

