[Test]
    public void TestComputeFireTimesBetweenDstTransition()
    {
        // Use CET timezone where DST ends on Oct 25, 2020 (clocks go back from CEST UTC+2 to CET UTC+1)
        var timeZoneInfo = TZConvert.GetTimeZoneInfo("Central European Standard Time");

        DateTime startDateTime = new DateTime(2020, 10, 25);
        DateTimeOffset startDateTimeOffset = new DateTimeOffset(startDateTime, timeZoneInfo.GetUtcOffset(startDateTime));
        int daysAhead = 3;

        IOperableTrigger trigger = (IOperableTrigger) TriggerBuilder.Create()
            .WithIdentity("id")
            .ForJob("job")
            .StartAt(new DateTimeOffset(new DateTime(2020, 10, 25, 0, 1, 5), timeZoneInfo.GetUtcOffset(new DateTime(2020, 10, 25, 0, 1, 5))))
            .WithDailyTimeIntervalSchedule(
                scheduleBuilder =>
                {
                    scheduleBuilder.OnEveryDay().WithIntervalInHours(24);
                    scheduleBuilder
                        .StartingDailyAt(new TimeOfDay(0, 1, 5))
                        .EndingDailyAt(new TimeOfDay(23, 59, 59))
                        .WithMisfireHandlingInstructionDoNothing()
                        .InTimeZone(timeZoneInfo);
                })
            .Build();

        IReadOnlyList<DateTimeOffset> fireTimes =
            TriggerUtils.ComputeFireTimesBetween(
                trigger,
                null,
                startDateTimeOffset,
                startDateTimeOffset.AddDays(daysAhead));

        // Should get 3 dates - Oct 25, 26, 27 at 0:01:05 local time
        Assert.Multiple(() =>
        {
            Assert.That(fireTimes.Count, Is.EqualTo(3), "Should have exactly 3 fire times");

            Assert.That(fireTimes[0].LocalDateTime, Is.EqualTo(new DateTimeOffset(new DateTime(2020, 10, 25, 0, 1, 5), timeZoneInfo.GetUtcOffset(new DateTime(2020, 10, 25, 0, 1, 5))).LocalDateTime));
            Assert.That(fireTimes[1].LocalDateTime, Is.EqualTo(new DateTimeOffset(new DateTime(2020, 10, 26, 0, 1, 5), timeZoneInfo.GetUtcOffset(new DateTime(2020, 10, 26, 0, 1, 5))).LocalDateTime));
            Assert.That(fireTimes[2].LocalDateTime, Is.EqualTo(new DateTimeOffset(new DateTime(2020, 10, 27, 0, 1, 5), timeZoneInfo.GetUtcOffset(new DateTime(2020, 10, 27, 0, 1, 5))).LocalDateTime));
        });
    }

    private sealed class FixedTimeProvider(DateTimeOffset utcNow) : TimeProvider
    {
        public override DateTimeOffset GetUtcNow() => utcNow;
    }
}

