            DateTime localFireDateTime = localBaseDateTime.AddSeconds(RepeatInterval * (int) jumpCount);
            fireTime = new DateTimeOffset(localFireDateTime, TimeZoneUtil.GetUtcOffset(localFireDateTime, TimeZone));
        }
        else if (repeatUnit == IntervalUnit.Minute)
        {
            jumpCount = secondsAfterStart / (repeatLong * 60L);
            if (secondsAfterStart % (repeatLong * 60L) != 0)
            {
                jumpCount++;
            }
            DateTime localFireDateTime = localBaseDateTime.AddMinutes(RepeatInterval * (int) jumpCount);
            fireTime = new DateTimeOffset(localFireDateTime, TimeZoneUtil.GetUtcOffset(localFireDateTime, TimeZone));
        }
        else if (repeatUnit == IntervalUnit.Hour)
        {
            jumpCount = secondsAfterStart / (repeatLong * 60L * 60L);
            if (secondsAfterStart % (repeatLong * 60L * 60L) != 0)
            {
                jumpCount++;
            }
            DateTime localFireDateTime = localBaseDateTime.AddHours(RepeatInterval * (int) jumpCount);
            fireTime = new DateTimeOffset(localFireDateTime, TimeZoneUtil.GetUtcOffset(localFireDateTime, TimeZone));
        }

